■ 共通土台(4ファイルとも同じ): `const { buildEngine, mulberry32, ROOT } = require('./_sim_engine.js'); const data = require(path.join(ROOT, process.env.PCHAM_DATA || 'pokechan_data.js')); const E = buildEngine();` — E は real_battle_simulator のエンジンを Node に載せたもの。乱数は E.setRandom(mulberry32(seed)) で決定論固定(定数関数 `()=>0` で分岐強制も可)。期待値は必ず権威ソース(Bulbapedia/ポケモンWiki)からコメントに出典を書く(sim自己出力をゴールデンにしない=羅針盤原則)。

■ スタイル1: check形式(_sim_interaction_test.js / _sim_status_multiturn_test.js)。pass/failカウンタ+exit code(fail>0で1)。
【セットアップ】
```js
function freshSide(pokeName, moveKey, opts) {   // _sim_interaction_test.js:30
  const s = E.makeSideState();
  s.poke = data.POKEMON_LIST.find(p => p.name === pokeName);
  s.moves = moveKey ? [data.WAZA_MAP[moveKey]] : [];
  s.selectedMoveIdx = 0;
  if (opts?.ability !== undefined) s.ability = opts.ability; else s.ability = s.poke.ab1 || '';
  if (opts?.item !== undefined) s.item = opts.item;   // 例 'focus_sash','life_orb','berry_sitrus'
  return s;
}
resetEnv();                       // E.env の weather/field/trickRoom/gravity/magicRoom 等を全リセット+setLastMoveAnywhere(null)
const atk = freshSide('カイリュー', 'jishin', { item: 'kodawari_hachimaki' });
atk.rank.atk = 6;                 // ランク直接設定可
fullHp(atk);                      // s.currentHp = E.realStat(s,'hp')
E.sides.self = atk; E.sides.opp = def;   // エンジンに両サイドを差す
E.setRandom(mulberry32(20260608));
```
【行動(用途で使い分け)】
- `E.calcDamage('self','opp', move)` → `{min,max,immune,reason,orbRecoil,...}`(副作用なしのダメージレンジ検証)
- `E.phaseDealDamage('self','opp', move)`(1回の攻撃解決: タスキ/がんじょう/接触反応/反動まで)
- `E.phaseApplyEffects('self','opp', move)`(変化技効果: バインド/ちょうはつ/アンコール/やどりぎ付与)
- `E.phaseSlipFor('opp')`(ターン終了スリップ: 状態異常/天候/slips配列)
- `E.runTurn()`(1ターン丸ごと: 行動順・まひ/ねむり判定・アイテム反応・end-of-turn)
- `E.runSingleAttack('self', moveIdx)`(片側だけ1技実行。失敗ログ検証に便利)
- `E.phaseInitA('self')`(登場時特性: トレース/かわりもの) / `E.phaseHitCheck(move, atkSide, defSide)` / `E.decideOrder(m1,m2)` / `E.effectiveSpeed(s)` / `E.aiScoreMove('self', move)`
【アサーション】
```js
check('S18-T1 ○○×△△: 期待挙動 [出典: Bulbapedia "..."]',
  def.currentHp === 1 && !def.fainted,          // 条件(bool)
  `hp=${def.currentHp} fainted=${def.fainted}`); // 失敗時detail
// ログ検証: E.battleLog.some(e => /技名！ しかし うまく きまらなかった/.test(e.msg))。E.battleLog.length=0 でクリア
// 状態は英語コード比較: 'burn'/'poison'/'badpoison'/'paralysis'/'sleep'/'freeze'、slipsは s.slips.find(sl=>sl.source==='バインド')、fraction/turns を数値検証
```
新ケースは末尾のブロック `{...}` を1つ足して check() を並べるだけ(ランナー登録不要・上から逐次実行)。

■ スタイル2: verdict形式(_ability_interaction_test.js / _item_interaction_test.js)。TESTS配列にpush→reference/_*_result.json に implemented/missing/broken/skip を書き出す(exit codeは常に0=合否でなく実装状況の棚卸し)。
```js
(function() {   // 新特性ケースの型(_ability_interaction_test.js:122 のパターン)
  const moves = movesWhere(m => m.flags && m.flags.punch && m.category === '物理' && m.power > 0);
  const results = moves.map(mv => {
    const base   = calcDmg('カイリキー', '',         mv, 'カビゴン', '', 9901);   // calcDmg(atkPoke, atkAb, move, defPoke, defAb, seed [, atkItem, defItem])
    const withAb = calcDmg('カイリキー', 'てつのこぶし', mv, 'カビゴン', '', 9901);
    const ok = ratioOk(base, withAb, 1.19, 1.21);   // 期待倍率±0.05許容
    return { move: mv.name, base, withAb, ratio: base>0 ? +(withAb/base).toFixed(3) : null, ok };
  });
  TESTS.push({
    ability: 'てつのこぶし', move_class: 'パンチ(punch)', type: 'power_multiplier', expected_ratio: 1.2,
    verdict: results.some(r=>r.ok===true) && !results.some(r=>r.ok===false) ? 'implemented' : results.some(r=>r.ok===false) ? 'broken' : 'missing',
    moves_tested: results, note: '出典と実装行番号'
  });
})();
```
補助: `setupBattle(atkPoke, atkAb, atkMove, defPoke, defAb, defMove [, atkItem, defItem])`(rank/status/HPを毎回初期化)、`tryContact(defAb, atkPoke, atkAb, move, checkFn, n)`(接触反応をNseed試行)、`testImmunity(defAb, move)`、`testStatusBlocked(defAb, moveName)`、`moveWith(pred)/movesWhere(pred,n)/pokeWith(ab)`。itemテストは calcDmg 第7/8引数に itemキー(items_database.jsのkey)を渡す。

■ 注意: verdict形式2本は実行のたび reference/_ability_interaction_result.json / _item_interaction_result.json を上書き再生成する(sim/データ本体は無変更)。ファイル冒頭に「読み取り専用・commit禁止」の注記あり。
